#include <stdio.h>
#include <stdint.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        uint32_t A[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                scanf("%u", &A[i][j]);
            }
        }
        uint32_t max_xor = 0;
        for (int x1 = 0; x1 < N; x1++) {
            for (int y1 = 0; y1 < N; y1++) {
                for (int x2 = x1; x2 < N; x2++) {
                    for (int y2 = y1; y2 < N; y2++) {
                        uint32_t xor = 0;
                        for (int i = x1; i <= x2; i++) {
                            for (int j = y1; j <= y2; j++) {
                                xor ^= A[i][j];
                            }
                        }
                        max_xor = (max_xor > xor) ? max_xor : xor;
                    }
                }
            }
        }
        printf("%u\n", max_xor);
    }
    return 0;
}

